-- STORES (1306 lojas reais dos clientes)
CREATE TABLE IF NOT EXISTS stores (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT,
  brand TEXT,
  address TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  code TEXT,
  corporate_name TEXT,
  cnpj TEXT,
  state TEXT,
  neighborhood TEXT,
  zip_code TEXT,
  email TEXT,
  phone TEXT,
  lat DOUBLE PRECISION,
  lng DOUBLE PRECISION,
  deleted_at TIMESTAMPTZ
);

-- JOBS (Ordens de Serviço de Campo)
CREATE TABLE IF NOT EXISTS jobs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  store_id UUID REFERENCES stores(id),
  os_number TEXT NOT NULL,
  type TEXT NOT NULL,
  status TEXT DEFAULT 'Pendente',
  scheduled_date DATE DEFAULT CURRENT_DATE,
  notes TEXT,
  issues TEXT,
  lat DOUBLE PRECISION,
  lng DOUBLE PRECISION,
  created_at TIMESTAMPTZ DEFAULT now(),
  assigned_to UUID REFERENCES auth.users(id),
  signature_url TEXT,
  started_at TIMESTAMPTZ,
  finished_at TIMESTAMPTZ,
  deleted_at TIMESTAMPTZ
);

-- JOB_PHOTOS (Fotos das instalações)
CREATE TABLE IF NOT EXISTS job_photos (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id UUID REFERENCES jobs(id),
  photo_type TEXT NOT NULL,
  photo_url TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  description TEXT,
  note TEXT
);

-- JOB_VIDEOS
CREATE TABLE IF NOT EXISTS job_videos (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  job_id UUID REFERENCES jobs(id),
  video_url TEXT NOT NULL,
  description TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- COMPANY_SETTINGS
CREATE TABLE IF NOT EXISTS company_settings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT,
  cnpj TEXT,
  phone TEXT,
  address TEXT,
  updated_at TIMESTAMPTZ DEFAULT now(),
  watermark_enabled BOOLEAN DEFAULT true
);

-- AUDIT_LOGS (Campo)
CREATE TABLE IF NOT EXISTS campo_audit_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES auth.users(id),
  action TEXT NOT NULL,
  target_id UUID NOT NULL,
  old_value JSONB,
  new_value JSONB,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- RLS
ALTER TABLE stores ENABLE ROW LEVEL SECURITY;
ALTER TABLE jobs ENABLE ROW LEVEL SECURITY;
ALTER TABLE job_photos ENABLE ROW LEVEL SECURITY;
ALTER TABLE job_videos ENABLE ROW LEVEL SECURITY;
ALTER TABLE company_settings ENABLE ROW LEVEL SECURITY;
ALTER TABLE campo_audit_logs ENABLE ROW LEVEL SECURITY;

-- RLS Policies: autenticados leem tudo, admin gerencia
CREATE POLICY "authenticated_read_stores" ON stores FOR SELECT TO authenticated USING (true);
CREATE POLICY "admin_all_stores" ON stores FOR ALL TO authenticated USING (
  EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role IN ('admin','admin'))
) WITH CHECK (true);

CREATE POLICY "authenticated_read_jobs" ON jobs FOR SELECT TO authenticated USING (true);
CREATE POLICY "instalador_update_jobs" ON jobs FOR UPDATE TO authenticated USING (assigned_to = auth.uid() OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role = 'admin'));
CREATE POLICY "admin_all_jobs" ON jobs FOR ALL TO authenticated USING (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role = 'admin'));

CREATE POLICY "authenticated_read_photos" ON job_photos FOR SELECT TO authenticated USING (true);
CREATE POLICY "authenticated_insert_photos" ON job_photos FOR INSERT TO authenticated WITH CHECK (true);

CREATE POLICY "authenticated_read_videos" ON job_videos FOR SELECT TO authenticated USING (true);
CREATE POLICY "authenticated_insert_videos" ON job_videos FOR INSERT TO authenticated WITH CHECK (true);

CREATE POLICY "authenticated_read_settings" ON company_settings FOR SELECT TO authenticated USING (true);
CREATE POLICY "admin_all_settings" ON company_settings FOR ALL TO authenticated USING (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role = 'admin'));

-- Storage bucket
CREATE POLICY "public_read_photos" ON storage.objects FOR SELECT USING (bucket_id = 'job_photos');
CREATE POLICY "authenticated_upload_photos" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'job_photos');
CREATE POLICY "authenticated_update_photos" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'job_photos');
CREATE POLICY "authenticated_delete_photos" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'job_photos');


